+                    return Err(FrankenError::DatabaseCorrupt {
+                        detail: "compact table leaf cell offset exceeds usable page size"
+                            .to_owned(),
+                    });
+                }
+                let seen_word = &mut seen_offsets[ptr / 64];
+                let seen_bit = 1_u64 << (ptr % 64);
+                if (*seen_word & seen_bit) != 0 {
+                    return Err(FrankenError::DatabaseCorrupt {
+                        detail:
